-- System Variables

SHOW VARIABLES; -- Or SHOW LOCAL VARIABLES, or SHOW SESSION VARIABLES

SHOW GLOBAL VARIABLES;

SHOW VARIABLES LIKE 'max%';

select @@max_allowed_packet;

set global max_allowed_packet = 16384; -- Must be n * 1024

select @@global.max_allowed_packet;

